import 'dart:convert'; import 'package:http/http.dart' as http; import '../config.dart'; import '../models/product.dart';
class ApiService { static Future<List<Product>> getProducts() async { final res = await http.get(Uri.parse("\${AppConfig.baseUrl}/api/products")); if (res.statusCode == 200) return (jsonDecode(res.body) as List).map((e) => Product.fromJson(e)).toList(); throw Exception("Error menú"); } static Future<String> createOrder(Map<String, dynamic> payload) async { final res = await http.post(Uri.parse("\${AppConfig.baseUrl}/api/orders"), headers: {"Content-Type": "application/json"}, body: jsonEncode(payload)); if (res.statusCode == 201) return (jsonDecode(res.body)['order_id'] as String); throw Exception("Error pedido"); } static Future<void> updateItemStatus(String itemId, String status) async { await http.patch(Uri.parse("\${AppConfig.baseUrl}/api/orders/DUMMY/items/\$itemId?status=\$status")); } }
